import React from "react";
import ReactDom from "react-dom/client";

function App() {
  return (
    <div>
      <h1>Hello React!</h1>
      <Pizza />
    </div>
  );
}

function Pizza() {
  return (
    <h1>
      Pizza
      <span role="img" aria-label="emoji">
        🍕
      </span>
    </h1>
  );
}

const root = ReactDom.createRoot(document.getElementById("root"));
root.render(<App />);
